#include <stdio.h>

int main(void) {
    int rounds;
    scanf("%d", &rounds);

    int playerScore = 0;
    int computerScore = 0;

    for (int i = 0; i < rounds; i++) {
        int playerChoice, computerChoice;
        scanf("%d", &playerChoice);

        // Randomize computer choice
        computerChoice = rand() % 3 + 1;

        printf("Player chose: %d\n", playerChoice);
        printf("Computer chose: %d\n", computerChoice);

        if (playerChoice == computerChoice) {
            printf("It's a tie!\n");
        } else if ((playerChoice == 1 && computerChoice == 3) ||
                   (playerChoice == 2 && computerChoice == 1) ||
                   (playerChoice == 3 && computerChoice == 2)) {
            playerScore++;
            printf("Player wins this round!\n");
        } else {
            computerScore++;
            printf("Computer wins this round!\n");
        }

        printf("Current score: Player %d, Computer %d\n", playerScore, computerScore);
    }

    if (playerScore > computerScore) {
        printf("Final result: Player wins!\n");
    } else if (computerScore > playerScore) {
        printf("Final result: Computer wins!\n");
    } else {
        printf("Final result: It's a tie!\n");
    }

    return 0;
}

